+        strength,
+        score,
+        entropyBits,
+        suggestions,
+        checks: {
+            hasLowercase: hasLower,
+            hasUppercase: hasUpper,
+            hasDigit: hasDigit,
+            hasSpecial: hasSpecial,
+            length: length,
+            meetsMinLength: length >= 12,
+        },
+    };
