+        // Update meter bar
+        if (meterBar) {
+            meterBar.style.width = `${percent}%`;
+            meterBar.style.backgroundColor = color;
+            meterBar.dataset.strength = strength;
+        }
+
+        // Update label
+        if (labelElement) {
+            labelElement.textContent = getStrengthLabel(strength);
+            labelElement.style.color = color;
+        }
